from vex import VexClient
from ag2 import register_global_hook

vex_client = VexClient(api_key="vex_123")

def vex_message_hook(message: dict) -> dict:
    checks = {
        "accuracy": "high",
        "safety": "strict",
        "coherence": "conversation",
        "pii_protection": "redact"
    }
