from ag2 import GroupChat
from vex import ConsensusVerifier

class SafeGroupChat(GroupChat):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.vex_consensus = ConsensusVerifier(
            min_agreement=0.8,
            checks=["fact_consensus", "safety_alignment"]
        )

    def select_speaker(self, last_speaker, selector):
        selection = super().select_speaker(last_speaker, selector)
        return self.vex_consensus.verify_selection(selection)

safe_chat = SafeGroupChat(agents=[chatbot, retriever, memory])
